+fn make_loaded_policy() -> PolicyConfig {
+    let mut config = PolicyConfig::default();
+    // Slightly different tuning: more aggressive conformal, faster recovery
+    config.conformal.alpha = 0.03;
+    config.cascade.recovery_threshold = 8;
+    config
+}
